			.list_label {
			}
			// 输入框
			.list_inp {
			}
		}
		// 验证码
		.listCode_view {
			// label
			.listCode_label {
			}
			// 验证码输入框
			.listCode_inp {
			}
			// 验证码按钮
			.listCode_btn {
			}
		}
		.list_type {
			.list_label {
			}
			// 下拉框样式
			:deep(.el-select) {
				//去掉默认样式
				.select-trigger{
					height: 100%;
					.el-input{
						height: 100%;

					}
				}
			}
		}
		// 记住密码样式
		.remember_view {
			width: 100%;
			text-align: center;
			order: 3;
		
			// 未选中样式
			:deep(.el-checkbox) {
				margin: 0;
				display: flex;
				width: 20%;
				justify-content: center;
				align-items: center;
				// 复选框
				.el-checkbox__inner {
					border: 1px solid #DCDFE6;
					background: #fff;
				}
				// 提示文字
				.el-checkbox__label{
					color: #999;
				}
			}
			// 选中样式
			:deep(.is-checked) {
				//复选框
				.el-checkbox__inner {
					background-color: var(--theme);
					border-color: var(--theme);
				}
				// 提示文字
				.el-checkbox__label{
					color: var(--theme);
				}
			}
		}
		// 按钮盒子
		.btn_view {
			// 登录
			.login {
			}
			// 注册
			.register {
			}
		}
	}

