<template>
	<div class="edit_view" :style='{}'>
        <div class="breadcrumb-wrapper" style="width: 100%;">
            <div class="bread_view">
                <el-breadcrumb separator="" class="breadcrumb">
                    <el-breadcrumb-item class="first_breadcrumb" :to="{ path: '/' }">首页</el-breadcrumb-item>
                    <el-breadcrumb-item class="second_breadcrumb" v-for="(item,index) in breadList" :key="index">{{item.name}}</el-breadcrumb-item>
                </el-breadcrumb>
            </div>
        </div>
		<el-form ref="formRef" :model="form" class="add_form" label-width="120px" :rules="rules">
			<el-row>
				<el-col :span="12">
					<el-form-item label="作品名称" prop="zuopinmingcheng">
						<el-input class="list_inp"
                                  v-model="form.zuopinmingcheng"
                                  placeholder="作品名称"
                                  type="text"
							      :readonly="!isAdd||disabledForm.zuopinmingcheng?true:false" />
					</el-form-item>
				</el-col>

				<el-col :span="12">
					<el-form-item label="作品分类" prop="zuopinfenlei">
						<el-select
							class="list_sel"
							:disabled="!isAdd||disabledForm.zuopinfenlei?true:false"
							v-model="form.zuopinfenlei" 
							placeholder="请选择作品分类"
							style="width:100%;"
							>
							<el-option v-for="(item,index) in zuopinfenleiLists" :label="item"
								:value="item"
								>
							</el-option>
						</el-select>
					</el-form-item>
				</el-col>
				<el-col :span="12">
					<el-form-item label="标签" prop="biaoqian">
						<el-select
							class="list_sel"
							:disabled="!isAdd||disabledForm.biaoqian?true:false"
							v-model="form.biaoqian" 
							placeholder="请选择标签"
							style="width:100%;"
							>
							<el-option v-for="(item,index) in biaoqianLists" :label="item"
								:value="item"
								>
							</el-option>
						</el-select>
					</el-form-item>
				</el-col>
				<el-col :span="12">
					<el-form-item label="摄影地点" prop="sheyingdidian">
						<el-input class="list_inp"
                                  v-model="form.sheyingdidian"
                                  placeholder="摄影地点"
                                  type="text"
							      :readonly="!isAdd||disabledForm.sheyingdidian?true:false" />
					</el-form-item>
				</el-col>

				<el-col :span="12">
					<el-form-item label="摄影时间" prop="sheyingshijian">
						<el-date-picker
							class="list_date"
							v-model="form.sheyingshijian"
							format="YYYY-MM-DD HH:mm:ss"
							value-format="YYYY-MM-DD HH:mm:ss"
							type="datetime"
							style="width:100%;"
							:readonly="!isAdd||disabledForm.sheyingshijian?true:false"
							placeholder="请选择摄影时间" />
					</el-form-item>
				</el-col>
				<el-col :span="12">
					<el-form-item label="封面" prop="fengmian">
						<uploads
							:disabled="!isAdd||disabledForm.fengmian?true:false"
							action="file/upload" 
							tip="请上传封面"
							style="width: 100%;text-align: left;"
							:fileUrls="form.fengmian?form.fengmian:''" 
							@change="fengmianUploadSuccess">
						</uploads>
					</el-form-item>
				</el-col>
				<el-col :span="12">
					<el-form-item label="发布时间" prop="fabushijian">
						<el-date-picker
							class="list_date"
							v-model="form.fabushijian"
							format="YYYY-MM-DD HH:mm:ss"
							value-format="YYYY-MM-DD HH:mm:ss"
							type="datetime"
							style="width:100%;"
							:readonly="!isAdd||disabledForm.fabushijian?true:false"
							placeholder="请选择发布时间" />
					</el-form-item>
				</el-col>
				<el-col :span="12">
					<el-form-item label="摄影师账号" prop="sheyingshizhanghao">
						<el-input class="list_inp"
                                  v-model="form.sheyingshizhanghao"
                                  placeholder="摄影师账号"
                                  type="text"
							      :readonly="!isAdd||disabledForm.sheyingshizhanghao?true:false" />
					</el-form-item>
				</el-col>

				<el-col :span="12">
					<el-form-item label="摄影师姓名" prop="sheyingshixingming">
						<el-input class="list_inp"
                                  v-model="form.sheyingshixingming"
                                  placeholder="摄影师姓名"
                                  type="text"
							      :readonly="!isAdd||disabledForm.sheyingshixingming?true:false" />
					</el-form-item>
				</el-col>

				<el-col :span="24">
					<el-form-item label="作品影简介" prop="zuopinyingjianjie">
						<el-input v-model="form.zuopinyingjianjie" placeholder="作品影简介" type="textarea"
						:readonly="!isAdd||disabledForm.zuopinyingjianjie?true:false"
						/>
					</el-form-item>
				</el-col>
				<el-col :span="24">
					<el-form-item label="摄影作品" prop="sheyingzuopin">
						<editor class="list_editor" :value="form.sheyingzuopin" placeholder="请输入摄影作品" :readonly="!isAdd||disabledForm.sheyingzuopin?true:false"
							@change="(e)=>editorChange(e,'sheyingzuopin')"></editor>
					</el-form-item>
				</el-col>
			</el-row>
			<div class="formModel_btn_box">
				<el-button class="formModel_cancel" @click="backClick">取消</el-button>
				<el-button class="formModel_confirm"
                           @click="save"
                           type="success"
				>
					保存
				</el-button>
			</div>
		</el-form>
	</div>
</template>
<script setup>
	import {
		ref,
		getCurrentInstance,
		watch,
		onUnmounted,
		onMounted,
		nextTick,
		computed
	} from 'vue';
	import {
		useRoute,
		useRouter
	} from 'vue-router';
    import moment from "moment";
	const context = getCurrentInstance()?.appContext.config.globalProperties;
	const route = useRoute()
	const router = useRouter()
	//基础信息
	const tableName = 'sheyingzuopin'
	const formName = '摄影作品'
	//基础信息
	const breadList = ref([{
		name: formName
	}])
	//获取唯一标识
	const getUUID =()=> {
      return new Date().getTime();
    }
	//form表单
	const form = ref({
		zuopinmingcheng: '',
		zuopinfenlei: '',
		biaoqian: '',
		sheyingdidian: '',
		sheyingshijian: '',
		fengmian: '',
		sheyingzuopin: '',
		fabushijian: '',
		sheyingshizhanghao: '',
		sheyingshixingming: '',
		zuopinyingjianjie: '',
		clicktime: '',
		shhf: '',
	})
	const formRef = ref(null)
	const id = ref(0)
	const type = ref('')
	const disabledForm = ref({
		zuopinmingcheng : false,
		zuopinfenlei : false,
		biaoqian : false,
		sheyingdidian : false,
		sheyingshijian : false,
		fengmian : false,
		sheyingzuopin : false,
		fabushijian : false,
		sheyingshizhanghao : false,
		sheyingshixingming : false,
		zuopinyingjianjie : false,
		thumbsupNumber : false,
		crazilyNumber : false,
		storeupNumber : false,
		discussNumber : false,
		clicktime : false,
		sfsh : false,
		shhf : false,
	})
	const isAdd = ref(false)
	//表单验证
	const rules = ref({
		zuopinmingcheng: [
			{required: true,message: '请输入',trigger: 'blur'}, 
		],
		zuopinfenlei: [
		],
		biaoqian: [
		],
		sheyingdidian: [
		],
		sheyingshijian: [
		],
		fengmian: [
		],
		sheyingzuopin: [
			{required: true,message: '请输入',trigger: 'blur'}, 
		],
		fabushijian: [
		],
		sheyingshizhanghao: [
		],
		sheyingshixingming: [
		],
		zuopinyingjianjie: [
		],
		thumbsupNumber: [
			{ validator: context.$toolUtil.validator.intNumber, trigger: 'blur' },
		],
		crazilyNumber: [
			{ validator: context.$toolUtil.validator.intNumber, trigger: 'blur' },
		],
		storeupNumber: [
			{ validator: context.$toolUtil.validator.intNumber, trigger: 'blur' },
		],
		discussNumber: [
			{ validator: context.$toolUtil.validator.intNumber, trigger: 'blur' },
		],
		clicktime: [
		],
		sfsh: [
		],
		shhf: [
		],
	})
	//作品分类列表
	const zuopinfenleiLists = ref([])
	//标签列表
	const biaoqianLists = ref([])
	//封面上传回调
	const fengmianUploadSuccess=(e)=>{
		form.value.fengmian = e
	}
	//methods

	//methods
	//获取info
	const getInfo = ()=>{
		context?.$http({
			url: `${tableName}/info/${id.value}`,
			method: 'get'
		}).then(res => {
			let reg=new RegExp('../../../file','g')
			res.data.data.sheyingzuopin = res.data.data.sheyingzuopin.replace(reg,'../../../cl258043101/file');
			form.value = res.data.data
		})
	}
	const crossRow = ref('')
	const crossTable = ref('')
	const crossTips = ref('')
	const crossColumnName = ref('')
	const crossColumnValue = ref('')
	//初始化
	const init = (formId=null,formType='add',formNames='',row=null,table=null,statusColumnName=null,tips=null,statusColumnValue=null) => {
			form.value.fabushijian = context?.$toolUtil.getCurDateTime()
		if(formId){
			id.value = formId
			type.value = formType
		}
		if(formType == 'add'){
			isAdd.value = true
		}else if(formType == 'info'){
			isAdd.value = false
			getInfo()
		}else if(formType == 'edit'){
			isAdd.value = true
			getInfo()
		}
		else if(formType == 'cross'){
			isAdd.value = true
			// getInfo()
			for(let x in row){
				if(x=='zuopinmingcheng'){
					form.value.zuopinmingcheng = row[x];
					disabledForm.value.zuopinmingcheng = true;
					continue;
				}
				if(x=='zuopinfenlei'){
					form.value.zuopinfenlei = row[x];
					disabledForm.value.zuopinfenlei = true;
					continue;
				}
				if(x=='biaoqian'){
					form.value.biaoqian = row[x];
					disabledForm.value.biaoqian = true;
					continue;
				}
				if(x=='sheyingdidian'){
					form.value.sheyingdidian = row[x];
					disabledForm.value.sheyingdidian = true;
					continue;
				}
				if(x=='sheyingshijian'){
					form.value.sheyingshijian = row[x];
					disabledForm.value.sheyingshijian = true;
					continue;
				}
				if(x=='fengmian'){
					form.value.fengmian = row[x];
					disabledForm.value.fengmian = true;
					continue;
				}
				if(x=='sheyingzuopin'){
					form.value.sheyingzuopin = row[x];
					disabledForm.value.sheyingzuopin = true;
					continue;
				}
				if(x=='fabushijian'){
					form.value.fabushijian = row[x];
					disabledForm.value.fabushijian = true;
					continue;
				}
				if(x=='sheyingshizhanghao'){
					form.value.sheyingshizhanghao = row[x];
					disabledForm.value.sheyingshizhanghao = true;
					continue;
				}
				if(x=='sheyingshixingming'){
					form.value.sheyingshixingming = row[x];
					disabledForm.value.sheyingshixingming = true;
					continue;
				}
				if(x=='zuopinyingjianjie'){
					form.value.zuopinyingjianjie = row[x];
					disabledForm.value.zuopinyingjianjie = true;
					continue;
				}
				if(x=='thumbsupNumber'){
					form.value.thumbsupNumber = row[x];
					disabledForm.value.thumbsupNumber = true;
					continue;
				}
				if(x=='crazilyNumber'){
					form.value.crazilyNumber = row[x];
					disabledForm.value.crazilyNumber = true;
					continue;
				}
				if(x=='storeupNumber'){
					form.value.storeupNumber = row[x];
					disabledForm.value.storeupNumber = true;
					continue;
				}
				if(x=='discussNumber'){
					form.value.discussNumber = row[x];
					disabledForm.value.discussNumber = true;
					continue;
				}
				if(x=='clicktime'){
					form.value.clicktime = row[x];
					disabledForm.value.clicktime = true;
					continue;
				}
			}
			if(row){
				crossRow.value = row
			}
			if(table){
				crossTable.value = table
			}
			if(tips){
				crossTips.value = tips
			}
			if(statusColumnName){
				crossColumnName.value = statusColumnName
			}
			if(statusColumnValue){
				crossColumnValue.value = statusColumnValue
			}
		}
		context?.$http({
			url: `${context?.$toolUtil.storageGet('frontSessionTable')}/session`,
			method: 'get'
		}).then(res => {
			var json = res.data.data
			if(json.hasOwnProperty('sheyingshizhanghao') && context?.$toolUtil.storageGet("frontRole")!="管理员"){
				form.value.sheyingshizhanghao = json.sheyingshizhanghao
				disabledForm.value.sheyingshizhanghao = true;
			}
			if(json.hasOwnProperty('sheyingshixingming') && context?.$toolUtil.storageGet("frontRole")!="管理员"){
				form.value.sheyingshixingming = json.sheyingshixingming
				disabledForm.value.sheyingshixingming = true;
			}
            if (localStorage.getItem('autoSave')) {
                localStorage.removeItem('autoSave')
                save()
            }
		})
		context?.$http({
			url: `option/zuopinfenlei/zuopinfenlei`,
			method: 'get'
		}).then(res=>{
			zuopinfenleiLists.value = res.data.data
		})
		context?.$http({
			url: `option/biaoqian/biaoqian`,
			method: 'get'
		}).then(res=>{
			biaoqianLists.value = res.data.data
		})
	}
	//初始化
	//取消
	const backClick = () => {
		history.back()
	}
	//富文本数据回调
	const editorChange = (e,name) =>{
		form.value[name] = e
	}
	//提交
	const save=()=>{
		if(form.value.fengmian!=null) {
			form.value.fengmian = form.value.fengmian.replace(new RegExp(context?.$config.url,"g"),"");
		}
		var table = crossTable.value
		var objcross = JSON.parse(JSON.stringify(crossRow.value))
		let crossUserId = ''
		let crossRefId = ''
		let crossOptNum = ''
		if(type.value == 'cross'){
			if(crossColumnName.value!=''){
				if(!crossColumnName.value.startsWith('[')){
					for(let o in objcross){
						if(o == crossColumnName.value){
							objcross[o] = crossColumnValue.value
						}
					}
					//修改跨表数据
					changeCrossData(objcross)
				}else{
					crossUserId = context?.$toolUtil.storageGet('userid')
					crossRefId = objcross['id']
					crossOptNum = crossColumnName.value.replace(/\[/,"").replace(/\]/,"")
				}
			}
		}
		formRef.value.validate((valid)=>{
			if(valid){
				if(crossUserId&&crossRefId){
					form.value.crossuserid = crossUserId
					form.value.crossrefid = crossRefId
					let params = {
						page: 1,
						limit: 1000, 
						crossuserid:form.value.crossuserid,
						crossrefid:form.value.crossrefid,
					}
					context?.$http({
						url: `${tableName}/page`,
						method: 'get', 
						params: params 
					}).then(res=>{
						if(res.data.data.total>=crossOptNum){
							context?.$toolUtil.message(`${crossTips.value}`,'error')
							return false
						}else{
							context?.$http({
								url: `${tableName}/${!form.value.id ? "save" : "update"}`,
								method: 'post', 
								data: form.value 
							}).then(res=>{
                                context?.$toolUtil.message(`操作成功`,'success')
                                history.back()
							})
						}
					})
				}else{
					context?.$http({
						url: `${tableName}/${!form.value.id ? "save" : "update"}`,
						method: 'post', 
						data: form.value 
					}).then(res=>{
                        context?.$toolUtil.message(`操作成功`,'success')
                        history.back()
					})
				}
			}
		})
	}
	//修改跨表数据
	const changeCrossData=(row)=>{
        if(type.value == 'cross'){
            context?.$http({
                url: `${crossTable.value}/update`,
                method: 'post',
                data: row
            }).then(res=>{})
        }
	}
	onMounted(()=>{
		type.value = route.query.type?route.query.type:'add'
		let row = null
		let table = null
		let statusColumnName = null
		let tips = null
		let statusColumnValue = null
		if(type.value == 'cross'){
			row = context?.$toolUtil.storageGet('crossObj')?JSON.parse(context?.$toolUtil.storageGet('crossObj')):{}
			table = context?.$toolUtil.storageGet('crossTable')
			statusColumnName = context?.$toolUtil.storageGet('crossStatusColumnName')
			tips = context?.$toolUtil.storageGet('crossTips')
			statusColumnValue = context?.$toolUtil.storageGet('crossStatusColumnValue')
		}
		init(route.query.id?route.query.id:null, type.value,'', row, table, statusColumnName, tips, statusColumnValue)
	})
    onUnmounted(()=>{
        Object.keys(localStorage).map(item=>{
            if(item.startsWith('cross')){
                localStorage.removeItem(item)
            }
        })
    })
</script>
